    float cz = .7+((q6-q7)*q2*.01+lum(main))*.5;
    vec2 cuv = vec2( (vUv.x -.5)*cz, (vUv.y-.5)*cz )+.5;
    vec3 color = texture(sampler_rand02, cuv ).xyz;
